def process_order(order_id, user_id, items, coupon_code=None):
    db = get_db()
    user = db.query('SELECT * FROM users WHERE id = ?', user_id)
    if not user:
        raise Exception('User not found')
    total = 0
    for item in items:
        product = db.query('SELECT * FROM products WHERE id = ?', item['product_id'])
        if not product:
            raise Exception(f'Product {item["product_id"]} not found')
        if product['stock'] < item['qty']:
            raise Exception(f'Insufficient stock for {product["name"]}')
        total += product['price'] * item['qty']
    if coupon_code:
        coupon = db.query('SELECT * FROM coupons WHERE code = ?', coupon_code)
        if coupon and coupon['expires_at'] > datetime.now():
            if coupon['type'] == 'percent':
                total = total * (1 - coupon['discount'] / 100)
            else:
                total = total - coupon['discount']
    tax = total * 0.08
    total_with_tax = total + tax
    order = db.insert('orders', {'id': order_id, 'user_id': user_id, 'total': total_with_tax, 'status': 'pending'})
    for item in items:
        db.insert('order_items', {'order_id': order_id, 'product_id': item['product_id'], 'qty': item['qty']})
    send_email(user['email'], 'Order Confirmation', f'Your order {order_id} totals ${total_with_tax:.2f}')
    return order
```

